class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False


class _Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _collect_words_from_node(self, node: TrieNode, current_word: str, results: list):
        if node.is_end_of_word:
            results.append(current_word)
        for char, child_node in node.children.items():
            self._collect_words_from_node(child_node, current_word + char, results)

    def search_by_pattern(self, pattern: str) -> list:
        node = self.root
        for char in pattern:
            if char not in node.children:
                return []
            node = node.children[char]

        results = []
        self._collect_words_from_node(node, pattern, results)
        return results


class PrefixSuffixTrie:
    def __init__(self):
        self.forward_trie = _Trie()
        self.reverse_trie = _Trie()

    def insert(self, word: str):
        self.forward_trie.insert(word)
        self.reverse_trie.insert(word[::-1])

    def search_prefix(self, prefix: str) -> list:
        return self.forward_trie.search_by_pattern(prefix)

    def search_suffix(self, suffix: str) -> list:
        reversed_suffix = suffix[::-1]
        raw_results = self.reverse_trie.search_by_pattern(reversed_suffix)
        return [word[::-1] for word in raw_results]


if __name__ == '__main__':
    trie = PrefixSuffixTrie()
    words_to_add = ["apple", "apply", "apricot", "banana", "band", "cat", "catch", "dog", "running", "singing"]

